tlDataChunk*
tlLightChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Pure3D::Light::DIRECTION:
        dch = new tlLightDirectionChunk(&ch);
        break;
    case Pure3D::Light::CONE_PARAM:
        dch = new tlLightConeParamChunk(&ch);
        break;
    case Pure3D::Light::POSITION:
        dch = new tlLightPositionChunk(&ch);
        break;
    case Pure3D::Light::SHADOW:
        dch = new tlLightShadowChunk(&ch);
        break;
    case Pure3D::Light::DECAY_RANGE:
        dch = new tlLightDecayRangeChunk(&ch);
        break;
    case Pure3D::Light::ILLUMINATION_TYPE:
        dch = new tlLightIlluminationTypeChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

