{

}

tlLightConeParamChunk::tlLightConeParamChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Light::CONE_PARAM);
    ident = Pure3D::Light::CONE_PARAM;

    tlFile* f = ch->GetFile();

    phi = f->GetFloat();
    theta = f->GetFloat();
    falloff = f->GetFloat();
    range = f->GetFloat();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Light::CONE_PARAM);
    }
}

void
tlLightConeParamChunk::Init()
{
    ident = Pure3D::Light::CONE_PARAM;
    phi = 0.0f;
    theta = 0.0f;
    falloff = 0.0f;
    range = 0.0f;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Light::CONE_PARAM);
    }
}

long 
tlLightConeParamChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( phi );
    s += sizeof( theta );
    s += sizeof( falloff );
    s += sizeof( range );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlLightConeParamChunk&
tlLightConeParamChunk::operator=(const tlLightConeParamChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    phi = a.phi;
    theta = a.theta;
    falloff = a.falloff;
    range = a.range;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlLightConeParamChunk::operator==(const tlDataChunk& a)
{

    const tlLightConeParamChunk* aptr = dynamic_cast<const tlLightConeParamChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(phi == aptr->phi))
    {
        return false;
    }
    if(!(theta == aptr->theta))
    {
        return false;
    }
    if(!(falloff == aptr->falloff))
    {
        return false;
    }
    if(!(range == aptr->range))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

