tlLightDecayRangeChunk::tlLightDecayRangeChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Light::DECAY_RANGE);
    ident = Pure3D::Light::DECAY_RANGE;

    tlFile* f = ch->GetFile();

    decayrangetype = f->GetLong();
    inner.Read(f);
    outer.Read(f);
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Light::DECAY_RANGE);
    }
}

void
tlLightDecayRangeChunk::Init()
{
    ident = Pure3D::Light::DECAY_RANGE;
    decayrangetype = 0;
    inner.Init( );
    outer.Init( );
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Light::DECAY_RANGE);
    }
}

long 
tlLightDecayRangeChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( decayrangetype );
    s += sizeof( inner );
    s += sizeof( outer );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlLightDecayRangeChunk&
tlLightDecayRangeChunk::operator=(const tlLightDecayRangeChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    decayrangetype = a.decayrangetype;
    inner = a.inner;
    outer = a.outer;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlLightDecayRangeChunk::operator==(const tlDataChunk& a)
{

    const tlLightDecayRangeChunk* aptr = dynamic_cast<const tlLightDecayRangeChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(decayrangetype == aptr->decayrangetype))
    {
        return false;
    }
    if(!(inner == aptr->inner))
    {
        return false;
    }
    if(!(outer == aptr->outer))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlLightDecayRangeChunk::NameCompare(const tlDataChunk& a)
{

    // This chunk has no name, so we must compare the bits
    return operator==(a);
}


